(gen_random_uuid(), 'A world without microbes is a world without life as we know it.', 'Louis Pasteur', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The discovery of the structure of DNA was a triumph of the scientific method.', 'Rosalind Franklin', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'discipline'], true, 'science'),
(gen_random_uuid(), 'Science is the poetry of reality.', 'Richard Dawkins', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['creativity', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'An understanding of the atom is not merely a matter of physics; it is the understanding of life itself.', 'Linus Pauling', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
