(gen_random_uuid(), 'Nature is relentless and unchangeable, and it is indifferent as to whether its hidden reasons and actions are understandable to man or not.', 'Galileo Galilei', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'I think nature''s imagination is so much greater than man''s — she''s never going to let us relax.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'When you get as abstract as you want, you lose something of the thrill of scientific discovery.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The most powerful tool we have is our ability to change our minds.', 'Jane Goodall', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'self_improvement', 'learning'], true, 'science'),
(gen_random_uuid(), 'We need the tonic of wildness — to wade sometimes in marshes where the bittern and the meadow-hen lurk.', 'Henry David Thoreau', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'What is life? It is the flash of a firefly in the night. It is the breath of a buffalo in the wintertime.', 'Crowfoot', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The history of science is the history of humanity''s attempt to understand the patterns of nature.', 'Isaac Asimov', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
