(gen_random_uuid(), 'The cosmos is all that is or ever was or ever will be.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
